-- Generated by OrchestKit Claude Plugin
-- Created: 2026-07-20

-- Routing edges view. The auto routers (/ork:auto, /hq-ext:auto) classify
-- in-prompt and hand off by invoking the next skill in the same session, so
-- the routing graph is derivable from skill_invocation alone: for each router
-- invocation, the next invocation in that session IS the route taken.
-- Materialized as a view so /ork:analytics (and ad-hoc sqlite3) can query
-- goal->route distribution with zero new writers.

PRAGMA user_version = 3;

CREATE VIEW IF NOT EXISTS routing_edge AS
SELECT
    a.session_id,
    a.skill        AS router,
    b.skill        AS routed_to,
    a.invoked_at   AS routed_at,
    b.invoked_at - a.invoked_at AS handoff_ms
FROM skill_invocation a
JOIN skill_invocation b
  ON b.session_id = a.session_id
 AND b.invoked_at > a.invoked_at
 AND b.invoked_at = (
      SELECT MIN(c.invoked_at)
      FROM skill_invocation c
      WHERE c.session_id = a.session_id
        AND c.invoked_at > a.invoked_at
 )
WHERE a.skill IN ('ork:auto', 'hq-ext:auto');
